VALUES
  ('fire-eq-tech-moex-02510', 'fire-eq-tech', 'fire-eq-tech-moex-100-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「消防安全設備檢修專業機構管理辦法」之規定，下列敘述何者錯誤？', '["消防安全設備檢修專業機構應置有專任之消防設備師及消防設備士合計達十人以上，其中消防設備師 至少二人", "消防安全設備檢修專業機構應備置檢修場所清冊及相關檢修報告，並至少保存三年", "消防安全設備檢修專業機構合格證書之有效期限為一年", "消防安全設備檢修專業機構聘用、資遣、解聘消防設備師或消防設備士，應於十五日內，報請內政部 備查"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "e0dea9d83693", "answer_pdf_sha1": "6427b1f6a133", "source_family": "moex-gov-tw", "moex": {"exam_code": "100090", "c": "902", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "100", "exam_name": "100年專技引水、驗船、第1次食品技師、消防設備、地政士、專責報關、保險人員、特考中醫、語言治療、聽力、牙體技術考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02511', 'fire-eq-tech', 'fire-eq-tech-moex-100-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「液化石油氣容器認可作業及管理要點」之規定，下列敘述何者錯誤？', '["經型式認可者，應自取得型式認可書之日起一年內申請個別認可，經個別認可合格並取得液化石油氣 容器瓶身證明者，始得申購合格標示", "申請人接獲液化石油氣容器個別認可試驗不合格通知後三個月內應辦理銷毀事宜", "取得個別認可之廠商應詳實紀錄液化石油氣容器銷售對象及數量， 於次月十五日前以書面陳報內政部 及內政部指定之專業機構", "型式認可之審查結果，自受理之日起三個月內由內政部以書面通知申請人"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "e0dea9d83693", "answer_pdf_sha1": "6427b1f6a133", "source_family": "moex-gov-tw", "moex": {"exam_code": "100090", "c": "902", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "100", "exam_name": "100年專技引水、驗船、第1次食品技師、消防設備、地政士、專責報關、保險人員、特考中醫、語言治療、聽力、牙體技術考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02512', 'fire-eq-tech', 'fire-eq-tech-moex-100-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「消防法」之規定，下列敘述何者錯誤？', '["消防主管機關：在中央為消防署；在直轄市為消防局", "應設置消防安全設備之供營業使用場所其管理權人未依規定設置或維護，於發生火災時致人於死者， 處一年以上七年以下有期徒刑，得併科新臺幣一百萬元以上五百萬元以下罰金", "消防設備師或消防設備士為消防安全設備不實檢修報告者，處新臺幣二萬元以上十萬元以下罰鍰", "地面樓層達十一層以上建築物、地下建築物及中央主管機關指定之場所，其管理權人應使用附有防焰 標示之地毯、窗簾、布幕、展示用廣告板及其他指定之防焰物品"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "e0dea9d83693", "answer_pdf_sha1": "6427b1f6a133", "source_family": "moex-gov-tw", "moex": {"exam_code": "100090", "c": "902", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "100", "exam_name": "100年專技引水、驗船、第1次食品技師、消防設備、地政士、專責報關、保險人員、特考中醫、語言治療、聽力、牙體技術考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02513', 'fire-eq-tech', 'fire-eq-tech-moex-100-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「公共危險物品及可燃性高壓氣體設置標準暨安全管理辦法」之規定，禁水性物質屬於第幾類公共危 險物品？', '["第一類", "第二類", "第三類", "第四類"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "e0dea9d83693", "answer_pdf_sha1": "6427b1f6a133", "source_family": "moex-gov-tw", "moex": {"exam_code": "100090", "c": "902", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "100", "exam_name": "100年專技引水、驗船、第1次食品技師、消防設備、地政士、專責報關、保險人員、特考中醫、語言治療、聽力、牙體技術考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02514', 'fire-eq-tech', 'fire-eq-tech-moex-100-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「各類場所消防安全設備設置標準」規定，公共危險物品等場所設置水霧滅火設備之緊急電源供電容 量應供其有效動作多少分鐘以上？', '["20", "30", "45", "60"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "e0dea9d83693", "answer_pdf_sha1": "6427b1f6a133", "source_family": "moex-gov-tw", "moex": {"exam_code": "100090", "c": "902", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "100", "exam_name": "100年專技引水、驗船、第1次食品技師、消防設備、地政士、專責報關、保險人員、特考中醫、語言治療、聽力、牙體技術考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02515', 'fire-eq-tech', 'fire-eq-tech-moex-100-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「公共危險物品及可燃性高壓氣體設置標準暨安全管理辦法」之規定，下列敘述何者錯誤？', '["六類物品製造場所不得設於建築物之地下層", "六類物品製造場所之窗戶及出入口應設置三十分鐘以上防火時效之防火門窗", "室外儲槽場所儲槽儲存第四類公共危險物品者，儲槽容量合計超過二十萬公秉者，防液堤之高度應在 一公尺以上", "地下儲槽場所之儲槽頂部距離地面應在一公尺以上"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "e0dea9d83693", "answer_pdf_sha1": "6427b1f6a133", "source_family": "moex-gov-tw", "moex": {"exam_code": "100090", "c": "902", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "100", "exam_name": "100年專技引水、驗船、第1次食品技師、消防設備、地政士、專責報關、保險人員、特考中醫、語言治療、聽力、牙體技術考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02516', 'fire-eq-tech', 'fire-eq-tech-moex-100-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「公共危險物品試驗方法及判定基準」之規定，下列敘述何者錯誤？', '["氧化性固體實施燃燒試驗時所使用之標準物質，特級為過氯酸鉀及1級為溴酸鉀", "氧化性固體實施落錘試驗時之標準物質，特級為硝酸鉀及1級為氯酸鉀", "氧化性固體實施落錘試驗時，較氯酸鉀敏感時，判定為第三級", "氧化性固體實施燃燒試驗時，燃燒時間較溴酸鉀短，判定為第一級"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "e0dea9d83693", "answer_pdf_sha1": "6427b1f6a133", "source_family": "moex-gov-tw", "moex": {"exam_code": "100090", "c": "902", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "100", "exam_name": "100年專技引水、驗船、第1次食品技師、消防設備、地政士、專責報關、保險人員、特考中醫、語言治療、聽力、牙體技術考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02517', 'fire-eq-tech', 'fire-eq-tech-moex-100-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依照「防焰性能試驗基準」，防焰物品之防焰性能規定，下列何者錯誤？', '["地毯等地坪舖設物類，碳化距離不得超過10公分", "展示用廣告板，碳化面積不得超過40平方公分", "厚纖維製品（每平方公尺質量超過450公克者），餘燃時間不得超過20秒", "薄纖維製品（每平方公尺質量450公克以下者），餘焰時間不得超過3秒"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "e0dea9d83693", "answer_pdf_sha1": "6427b1f6a133", "source_family": "moex-gov-tw", "moex": {"exam_code": "100090", "c": "902", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "100", "exam_name": "100年專技引水、驗船、第1次食品技師、消防設備、地政士、專責報關、保險人員、特考中醫、語言治療、聽力、牙體技術考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02518', 'fire-eq-tech', 'fire-eq-tech-moex-100-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「各類場所消防安全設備設置標準」規定，有關自動撒水設備之敘述何者錯誤？', '["撒水頭迴水板下方四十五公分內及水平方向三十公分內，應保持淨空間，不得有障礙物", "電信機械室或電腦室得免裝撒水頭", "撒水頭之放水量，每分鐘應在八十公升且放水壓力應在每平方公分一公斤以上", "快速反應型撒水頭（第一種感度），各層任一點至撒水頭之水平距離在二點一公尺以下"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "e0dea9d83693", "answer_pdf_sha1": "6427b1f6a133", "source_family": "moex-gov-tw", "moex": {"exam_code": "100090", "c": "902", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "100", "exam_name": "100年專技引水、驗船、第1次食品技師、消防設備、地政士、專責報關、保險人員、特考中醫、語言治療、聽力、牙體技術考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02519', 'fire-eq-tech', 'fire-eq-tech-moex-100-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「建築技術規則」之規定，下列有關緊急用昇降機之敘述何者錯誤？', '["建築物高度超過十層樓以上部分之最大一層樓地板面積，在1,500平方公尺以下者，至少應設置一座", "機間之四周應為具有一小時以上防火時效之牆壁及樓板，其天花板及牆裝修，應使用耐燃一級材料", "每座昇降機間之樓地板面積不得小於20平方公尺", "機間在避難層之位置，自昇降機出口或昇降機間之出入口至通往戶外出入口之步行距離不得大於30公尺"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "e0dea9d83693", "answer_pdf_sha1": "6427b1f6a133", "source_family": "moex-gov-tw", "moex": {"exam_code": "100090", "c": "902", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "100", "exam_name": "100年專技引水、驗船、第1次食品技師、消防設備、地政士、專責報關、保險人員、特考中醫、語言治療、聽力、牙體技術考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL)
